import { createClient } from '@supabase/supabase-js';

const URL = 'https://tuproyecto.supabase.co';
const CLAVE = 'tu-anon-key-publica';

const supabase = createClient(URL, CLAVE);

async function anadirPlanta(nombre, especie) {
  const { data, error } = await supabase
    .from('plantas')
    .insert({ nombre: nombre, especie: especie });

  if (error) {
    console.log('No se pudo guardar:', error.message);
  } else {
    console.log('Guardada:', data);
  }
}

anadirPlanta('Tomatera', 'Solanum');

async function cargarPlantas() {
  const { data, error } = await supabase
    .from('plantas')
    .select('*');

  if (error) return console.log(error.message);

  // data es una lista de objetos, como en el nivel 6
  const lista = document.querySelector('#lista');
  let html = '';
  for (const planta of data) {
    html += '<li>' + planta.nombre + '</li>';
  }
  lista.innerHTML = html;
}

cargarPlantas();

